B = 0x1122334455667788
H = (A ^ B) & (mod - 1)
inv31 = pow(31, -1, mod)
letters = list(range(65, 91)) + list(range(97, 123))
from functools import lru_cache
@lru_cache(maxsize=None)
def solve(S):
    if S == 0:
        return []
    d = S % 31
    # candidates that match residue
